class PiotrasClimateInfoEditor extends HTMLElement {
  constructor() { super();this.attachShadow({mode:'open'});this._config={};this._editingDeviceIndex=null;this._openSections={general:true,header:false,fonts:false,look:false,devices:false}; }
  setConfig(config) { this._config=JSON.parse(JSON.stringify(config));this._render(); }
  set hass(hass) { this._hass=hass; }
  _fire() { this.dispatchEvent(new CustomEvent('config-changed',{detail:{config:this._config},bubbles:true,composed:true})); }
  _set(key,value) { this._config={...this._config,[key]:value};this._fire();this._render(); }
  _addDevice() { const devices=JSON.parse(JSON.stringify(this._config.devices||[]));devices.push({name:'New device',entity_temp:'',icon_ha:'mdi:thermometer',icon_size:28,temp_cold_max:18,temp_cold_color:'#3498db',temp_comfort_max:23,temp_comfort_color:'#27ae60',temp_hot_color:'#e74c3c'});this._config={...this._config,devices};this._editingDeviceIndex=devices.length-1;this._fire();this._render(); }
  _deleteDevice(index) { const devices=JSON.parse(JSON.stringify(this._config.devices||[]));devices.splice(index,1);this._config={...this._config,devices};this._editingDeviceIndex=null;this._fire();this._render(); }
  _toggleSection(name) { this._openSections[name]=!this._openSections[name];this._render(); }
  _colorField(id,value,label) { const val=value||'';return `<div style="margin-bottom:10px;"><label style="display:block;font-size:11px;color:#888;margin-bottom:4px;">${label}</label><div style="display:flex;align-items:center;gap:8px;"><div id="preview_${id}" style="width:24px;height:24px;border-radius:4px;border:1px solid #555;background:${val||'#333'};flex-shrink:0;cursor:pointer;"></div><input type="color" id="picker_${id}" style="position:absolute;opacity:0;width:0;height:0;" value="${val&&val.startsWith('#')?val:'#ffffff'}"><input type="text" id="${id}" value="${val}" placeholder="e.g. #ffffff" style="flex:1;background:#1e1e1e;border:1px solid #444;border-radius:4px;color:#fff;padding:6px 8px;font-size:13px;"></div></div>`; }
  _section(id,title,content) { const open=this._openSections[id];return `<div style="border:1px solid #333;border-radius:8px;margin-bottom:8px;overflow:hidden;"><div id="toggle_${id}" style="padding:10px 14px;background:#1e1e1e;cursor:pointer;display:flex;justify-content:space-between;align-items:center;user-select:none;"><span style="font-weight:500;">${title}</span><span style="color:#888;font-size:16px;">${open?'▲':'▼'}</span></div>${open?`<div style="padding:14px;">${content}</div>`:''}</div>`; }
  _numField(id,value,label,min=0,max=999) { return `<div style="margin-bottom:10px;"><label style="display:block;font-size:11px;color:#888;margin-bottom:4px;">${label}</label><input type="number" id="${id}" value="${value??''}" min="${min}" max="${max}" style="width:100%;background:#1e1e1e;border:1px solid #444;border-radius:4px;color:#fff;padding:6px 8px;font-size:13px;box-sizing:border-box;"></div>`; }
  _textField(id,value,label,placeholder='') { return `<div style="margin-bottom:10px;"><label style="display:block;font-size:11px;color:#888;margin-bottom:4px;">${label}</label><input type="text" id="${id}" value="${value||''}" placeholder="${placeholder}" style="width:100%;background:#1e1e1e;border:1px solid #444;border-radius:4px;color:#fff;padding:6px 8px;font-size:13px;box-sizing:border-box;"></div>`; }
  _selectField(id,value,label,options) { const opts=options.map(o=>`<option value="${o.value}" ${o.value==value?'selected':''}>${o.label}</option>`).join('');return `<div style="margin-bottom:10px;"><label style="display:block;font-size:11px;color:#888;margin-bottom:4px;">${label}</label><select id="${id}" style="width:100%;background:#1e1e1e;border:1px solid #444;border-radius:4px;color:#fff;padding:6px 8px;font-size:13px;box-sizing:border-box;">${opts}</select></div>`; }
  _toggleField(id,value,label) { const on=value!==false;return `<div style="margin-bottom:10px;display:flex;align-items:center;justify-content:space-between;"><label style="font-size:13px;">${label}</label><label style="position:relative;display:inline-block;width:40px;height:22px;flex-shrink:0;"><input type="checkbox" id="${id}" ${on?'checked':''} style="opacity:0;width:0;height:0;"><span style="position:absolute;cursor:pointer;top:0;left:0;right:0;bottom:0;background:${on?'#4caf50':'#444'};border-radius:22px;transition:0.2s;"></span><span style="position:absolute;cursor:pointer;top:3px;left:${on?'21px':'3px'};width:16px;height:16px;background:#fff;border-radius:50%;transition:0.2s;"></span></label></div>`; }
  _devColorField(fieldId,value,label) { const val=value||'';return `<div style="margin-bottom:10px;"><label style="display:block;font-size:11px;color:#888;margin-bottom:4px;">${label}</label><div style="display:flex;align-items:center;gap:8px;"><div class="dev-color-preview" data-field="${fieldId}" style="width:24px;height:24px;border-radius:4px;border:1px solid #555;background:${val||'#333'};flex-shrink:0;cursor:pointer;"></div><input type="color" class="dev-color-picker" data-field="${fieldId}" style="position:absolute;opacity:0;width:0;height:0;" value="${val&&val.startsWith('#')?val:'#ffffff'}"><input type="text" class="dev-color-text" data-field="${fieldId}" value="${val}" placeholder="e.g. #3498db" style="flex:1;background:#1e1e1e;border:1px solid #444;border-radius:4px;color:#fff;padding:6px 8px;font-size:13px;"></div></div>`; }
  _twoCol(left,right) { return `<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;">${left}${right}</div>`; }
  _deviceForm(device) {
    const kwh=(device.kwh_sensors||[]).join('\n');
    return `<div style="background:#1a1a1a;border:1px solid #444;border-radius:8px;padding:14px;margin-top:8px;"><div style="font-size:12px;color:#888;margin-bottom:12px;">Editing: <b style="color:#fff;">${device.name||'Device'}</b></div>${this._textField('dev_name',device.name,'Name','e.g. Living room')}${this._textField('dev_entity_temp',device.entity_temp,'Temperature entity','sensor.xxx')}${this._textField('dev_entity_huma',device.entity_huma,'Humidity entity (optional)','sensor.xxx')}${this._textField('dev_entity_praca',device.entity_praca,'Active entity (binary_sensor, optional)','binary_sensor.xxx')}<div style="border-top:1px solid #333;margin:12px 0 10px;"></div><div style="font-size:11px;color:#888;margin-bottom:8px;font-weight:500;">HA Icon</div>${this._twoCol(this._textField('dev_icon_ha',device.icon_ha,'Icon (mdi:xxx)','mdi:sofa'),this._numField('dev_icon_size',device.icon_size??28,'Icon size (px)',12,80))}<div style="border-top:1px solid #333;margin:12px 0 10px;"></div><div style="font-size:11px;color:#888;margin-bottom:8px;font-weight:500;">🌡️ Temperature color zones</div><div style="background:#111;border-radius:6px;padding:10px;margin-bottom:8px;"><div style="font-size:11px;color:#3498db;margin-bottom:8px;">❄️ Cold zone — below threshold</div>${this._twoCol(this._numField('dev_temp_cold_max',device.temp_cold_max??18,'Max temp (°C)',-30,50),this._devColorField('temp_cold_color',device.temp_cold_color||'#3498db','Color'))}</div><div style="background:#111;border-radius:6px;padding:10px;margin-bottom:8px;"><div style="font-size:11px;color:#27ae60;margin-bottom:8px;">🌿 Comfort zone — between thresholds</div>${this._twoCol(this._numField('dev_temp_comfort_max',device.temp_comfort_max??23,'Max temp (°C)',-30,50),this._devColorField('temp_comfort_color',device.temp_comfort_color||'#27ae60','Color'))}</div><div style="background:#111;border-radius:6px;padding:10px;margin-bottom:8px;"><div style="font-size:11px;color:#e74c3c;margin-bottom:8px;">🔥 Hot zone — above comfort max</div>${this._devColorField('temp_hot_color',device.temp_hot_color||'#e74c3c','Color')}</div><div style="border-top:1px solid #333;margin:12px 0 10px;"></div><div style="font-size:11px;color:#888;margin-bottom:8px;font-weight:500;">Energy & Action</div><div style="margin-bottom:10px;"><label style="display:block;font-size:11px;color:#888;margin-bottom:4px;">kWh entities (one per line)</label><textarea id="dev_kwh" rows="3" placeholder="sensor.xxx&#10;sensor.yyy" style="width:100%;background:#1e1e1e;border:1px solid #444;border-radius:4px;color:#fff;padding:6px 8px;font-size:13px;box-sizing:border-box;resize:vertical;">${kwh}</textarea></div><div style="margin-bottom:10px;"><label style="display:block;font-size:11px;color:#888;margin-bottom:4px;">Tap action</label><select id="dev_tap" style="width:100%;background:#1e1e1e;border:1px solid #444;border-radius:4px;color:#fff;padding:6px 8px;font-size:13px;box-sizing:border-box;"><option value="more-info" ${(device.tap_action?.action??'more-info')==='more-info'?'selected':''}>more-info (default)</option><option value="none" ${device.tap_action?.action==='none'?'selected':''}>none (disabled)</option></select></div><div style="display:flex;gap:8px;margin-top:14px;"><button id="dev_save" style="flex:1;padding:8px;background:#4caf50;border:none;border-radius:6px;color:#fff;cursor:pointer;font-size:13px;font-weight:500;">💾 Save</button><button id="dev_cancel" style="flex:1;padding:8px;background:#444;border:none;border-radius:6px;color:#fff;cursor:pointer;font-size:13px;">✕ Cancel</button></div></div>`;
  }
  _render() {
    const c=this._config,devices=c.devices||[];
    const generalContent=`${this._selectField('card_layout',c.card_layout??1,'Layout',[{value:1,label:'1 – Name | Icon | Values'},{value:2,label:'2 – Icon | Name | Values'},{value:3,label:'3 – Name on top'}])}${this._numField('name_width',c.name_width??120,'Name column width (px)',50,300)}${this._selectField('name_align',c.name_align??1,'Name alignment',[{value:1,label:'Left'},{value:2,label:'Center'},{value:3,label:'Right'}])}${this._numField('icon_size',c.icon_size??28,'Default icon size (px)',12,80)}${this._numField('column_gap',c.column_gap??15,'Column gap (px)',0,60)}${this._numField('spacing',c.spacing??32,'Row spacing (px)',0,80)}<div style="border-top:1px solid #333;padding-top:10px;margin-top:4px;">${this._toggleField('show_name',c.show_name,'Show device names')}${this._toggleField('show_huma',c.show_huma,'Show humidity')}${this._toggleField('show_kwh',c.show_kwh,'Show energy (kWh)')}${this._toggleField('show_job',c.show_job,'Show active indicator ●')}${this._toggleField('show_icon_device',c.show_icon_device,'Show emoji icons 🌡️💧⚡')}${this._toggleField('show_icon_ha',c.show_icon_ha,'Show HA icon (mdi)')}</div>`;
    const headerContent=`${this._toggleField('show_header',c.show_header,'Show header')}${this._textField('header',c.header,'Header text')}${this._numField('header_font_size',c.header_font_size??16,'Header font size (px)',10,40)}${this._selectField('header_align',c.header_align??1,'Header alignment',[{value:1,label:'Left'},{value:2,label:'Center'},{value:3,label:'Right'}])}${this._colorField('header_font_color',c.header_font_color,'Header color')}`;
    const fontsContent=`${this._numField('font_size',c.font_size??13,'Value font size (px)',8,30)}${this._numField('font_size_name',c.font_size_name??14,'Name font size (px)',8,30)}${this._selectField('font_style',c.font_style??1,'Font style',[{value:1,label:'Normal'},{value:2,label:'Small-caps'},{value:3,label:'Monospace'}])}${this._colorField('device_name_color',c.device_name_color,'Device name color')}${this._colorField('value_color',c.value_color,'Value color')}`;
    const lookContent=`${this._colorField('background_color',c.background_color,'BG')}${this._twoCol(this._numField('border_radius',c.border_radius??'','Radius',0,50),this._numField('border_width',c.border_width??'','Width',0,20))}${this._colorField('border_color',c.border_color,'Border')}${this._textField('box_shadow',c.box_shadow,'Shadow','e.g. 0 2px 8px rgba(0,0,0,0.4)')}`;
    const devicesList=devices.map((d,i)=>{
      const isEditing=this._editingDeviceIndex===i,cold=d.temp_cold_color||'#3498db',comfort=d.temp_comfort_color||'#27ae60',hot=d.temp_hot_color||'#e74c3c';
      const dots=`<span title="Cold ≤${d.temp_cold_max??18}°C" style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${cold};margin-right:2px;"></span><span title="Comfort ≤${d.temp_comfort_max??23}°C" style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${comfort};margin-right:2px;"></span><span title="Hot" style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${hot};margin-right:6px;"></span>`;
      return `<div style="border:1px solid #333;border-radius:6px;padding:8px 10px;margin-bottom:6px;"><div style="display:flex;align-items:center;justify-content:space-between;"><div style="display:flex;align-items:center;gap:6px;min-width:0;">${dots}<div style="min-width:0;"><div style="font-size:13px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${d.name||'(no name)'}</div><div style="font-size:11px;color:#666;">${d.entity_temp||''}</div></div></div><div style="display:flex;gap:6px;flex-shrink:0;"><button id="edit_${i}" style="padding:4px 10px;background:#2196f3;border:none;border-radius:4px;color:#fff;cursor:pointer;font-size:12px;">✏️</button><button id="del_${i}" style="padding:4px 10px;background:#e53935;border:none;border-radius:4px;color:#fff;cursor:pointer;font-size:12px;">🗑️</button></div></div>${isEditing?this._deviceForm(d):''}</div>`;
    }).join('');
    const devicesContent=`${devicesList}<button id="add_device" style="width:100%;padding:8px;background:#333;border:1px dashed #555;border-radius:6px;color:#aaa;cursor:pointer;font-size:13px;margin-top:4px;">+ Add device</button>`;
    this.shadowRoot.innerHTML=`<style>:host{display:block;font-family:Segoe UI,Roboto,sans-serif;color:#fff;}*{box-sizing:border-box;}input,select,textarea{outline:none;}input:focus,select:focus,textarea:focus{border-color:#2196f3!important;}button:hover{opacity:0.85;}</style><div style="padding:4px;">${this._section('general','⚙️ General',generalContent)}${this._section('header','🔤 Header',headerContent)}${this._section('fonts','✏️ Fonts & Colors',fontsContent)}${this._section('look','🎨 Look',lookContent)}${this._section('devices','📱 Devices',devicesContent)}</div>`;
    this._attachListeners();
  }
  _attachListeners() {
    const sr=this.shadowRoot;
    ['general','header','fonts','look','devices'].forEach(id=>{const el=sr.getElementById(`toggle_${id}`);if(el)el.addEventListener('click',()=>this._toggleSection(id));});
    this._onChange('card_layout',v=>this._set('card_layout',parseInt(v)));this._onChange('name_width',v=>this._set('name_width',parseInt(v)));this._onChange('name_align',v=>this._set('name_align',parseInt(v)));this._onChange('icon_size',v=>this._set('icon_size',parseInt(v)));this._onChange('column_gap',v=>this._set('column_gap',parseInt(v)));this._onChange('spacing',v=>this._set('spacing',parseInt(v)));
    ['show_name','show_huma','show_kwh','show_job','show_icon_device','show_icon_ha','show_header'].forEach(id=>{const el=sr.getElementById(id);if(el)el.addEventListener('change',()=>this._set(id,el.checked));});
    this._onChange('header',v=>this._set('header',v));this._onChange('header_font_size',v=>this._set('header_font_size',parseInt(v)));this._onChange('header_align',v=>this._set('header_align',parseInt(v)));this._onColorField('header_font_color',v=>this._set('header_font_color',v));
    this._onChange('font_size',v=>this._set('font_size',parseInt(v)));this._onChange('font_size_name',v=>this._set('font_size_name',parseInt(v)));this._onChange('font_style',v=>this._set('font_style',parseInt(v)));this._onColorField('device_name_color',v=>this._set('device_name_color',v));this._onColorField('value_color',v=>this._set('value_color',v));
    this._onColorField('background_color',v=>this._set('background_color',v));this._onChange('border_radius',v=>{const n=parseInt(v);this._set('border_radius',isNaN(n)?undefined:n);});this._onChange('border_width',v=>{const n=parseInt(v);this._set('border_width',isNaN(n)?undefined:n);});this._onColorField('border_color',v=>this._set('border_color',v));this._onChange('box_shadow',v=>this._set('box_shadow',v));
    const devices=this._config.devices||[];
    devices.forEach((d,i)=>{const editBtn=sr.getElementById(`edit_${i}`),delBtn=sr.getElementById(`del_${i}`);if(editBtn)editBtn.addEventListener('click',()=>{this._editingDeviceIndex=this._editingDeviceIndex===i?null:i;this._render();});if(delBtn)delBtn.addEventListener('click',()=>this._deleteDevice(i));});
    sr.getElementById('add_device')?.addEventListener('click',()=>this._addDevice());
    if(this._editingDeviceIndex!==null){
      const i=this._editingDeviceIndex;
      sr.querySelectorAll('.dev-color-preview').forEach(preview=>{preview.addEventListener('click',()=>{sr.querySelector(`.dev-color-picker[data-field="${preview.dataset.field}"]`)?.click();});});
      sr.querySelectorAll('.dev-color-picker').forEach(picker=>{picker.addEventListener('input',()=>{const field=picker.dataset.field,text=sr.querySelector(`.dev-color-text[data-field="${field}"]`),prev=sr.querySelector(`.dev-color-preview[data-field="${field}"]`);if(text)text.value=picker.value;if(prev)prev.style.background=picker.value;});});
      sr.getElementById('dev_save')?.addEventListener('click',()=>{
        const get=id=>(sr.getElementById(id)?.value||'').trim(),getN=id=>parseFloat(sr.getElementById(id)?.value)||0,getDevColor=field=>(sr.querySelector(`.dev-color-text[data-field="${field}"]`)?.value||'').trim();
        const kwhRaw=sr.getElementById('dev_kwh')?.value||'',kwhList=kwhRaw.split('\n').map(s=>s.trim()).filter(Boolean),tapVal=sr.getElementById('dev_tap')?.value||'more-info';
        const updated={name:get('dev_name'),entity_temp:get('dev_entity_temp'),entity_huma:get('dev_entity_huma')||undefined,entity_praca:get('dev_entity_praca')||undefined,icon_ha:get('dev_icon_ha')||undefined,icon_size:parseInt(sr.getElementById('dev_icon_size')?.value)||28,temp_cold_max:getN('dev_temp_cold_max'),temp_cold_color:getDevColor('temp_cold_color')||'#3498db',temp_comfort_max:getN('dev_temp_comfort_max'),temp_comfort_color:getDevColor('temp_comfort_color')||'#27ae60',temp_hot_color:getDevColor('temp_hot_color')||'#e74c3c',kwh_sensors:kwhList.length?kwhList:undefined,tap_action:tapVal!=='more-info'?{action:tapVal}:undefined};
        Object.keys(updated).forEach(k=>updated[k]===undefined&&delete updated[k]);
        const devs=JSON.parse(JSON.stringify(this._config.devices||[]));devs[i]=updated;this._config={...this._config,devices:devs};this._editingDeviceIndex=null;this._fire();this._render();
      });
      sr.getElementById('dev_cancel')?.addEventListener('click',()=>{this._editingDeviceIndex=null;this._render();});
    }
  }
  _onChange(id,cb) { const el=this.shadowRoot.getElementById(id);if(el)el.addEventListener('change',()=>cb(el.value)); }
  _onColorField(id,cb) { const sr=this.shadowRoot,textInput=sr.getElementById(id),picker=sr.getElementById(`picker_${id}`),preview=sr.getElementById(`preview_${id}`);if(textInput)textInput.addEventListener('change',()=>{if(preview)preview.style.background=textInput.value||'#333';cb(textInput.value);});if(preview&&picker){preview.addEventListener('click',()=>picker.click());picker.addEventListener('input',()=>{if(textInput)textInput.value=picker.value;if(preview)preview.style.background=picker.value;cb(picker.value);});} }
}
customElements.define('piotras-climate-info-editor', PiotrasClimateInfoEditor);